// ─────────────────────────────────────────────
//  SHARED COMPONENTS
// ─────────────────────────────────────────────
function Logo({ size = "md" }) {
  const s = size === "lg" ? { img: 52, text: 26 } : { img: 36, text: 19 };
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
      <img
        src={KAI_LOGO_URI}
        alt="KaiLens"
        style={{ width: s.img, height: s.img, borderRadius: size === "lg" ? 14 : 10, boxShadow: `0 4px 14px ${C.teal}35`, objectFit: "cover", flexShrink: 0 }}
      />
      <span style={{ fontSize: s.text, fontWeight: 700, letterSpacing: "-0.3px", color: C.txt, fontFamily: "'Fredoka', system-ui, sans-serif" }}>Kai<span style={{ color: C.teal }}>Lens</span></span>
    </div>
  );
}

function Av({ initials, color, txtColor, size = 32 }) {
  return <div style={{ width: size, height: size, borderRadius: "50%", background: color, display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.34, fontWeight: 500, color: txtColor || "#fff", flexShrink: 0 }}>{initials}</div>;
}

function BackBtn({ onBack }) {
  return <div onClick={onBack} style={{ width: 32, height: 32, background: "rgba(0,0,0,0.5)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", border: `1px solid ${C.border}`, flexShrink: 0 }}><svg width="14" height="14" fill="none" stroke={C.txt} strokeWidth="2" viewBox="0 0 24 24"><polyline points="15 18 9 12 15 6"/></svg></div>;
}

function NavBar({ active, setActive, onScan }) {
  const leftTabs  = ["Kai", "Kitchen"];
  const rightTabs = ["Kollection", "Kalenda"];

  const TAB_COLORS = { Kai: C.coral, Kitchen: C.sky, Kollection: C.teal, Kalenda: C.lilac };

  const Tab = ({ name }) => {
    const isActive = active === name;
    const color = TAB_COLORS[name] || C.teal;
    return (
      <div onClick={() => setActive(name)} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 3, cursor: "pointer", paddingTop: 10, paddingBottom: 4 }}>
        <div style={{ width: 28, height: 28, display: "flex", alignItems: "center", justifyContent: "center", borderRadius: 10, background: isActive ? `${color}15` : "transparent", transition: "all 0.2s", color: isActive ? color : C.muted }}>
          {NAV_ICONS[name]}
        </div>
        <span style={{ fontSize: 9, fontWeight: isActive ? 700 : 500, color: isActive ? color : C.muted, fontFamily: "'Fredoka', sans-serif", letterSpacing: "0.2px" }}>{name}</span>
      </div>
    );
  };

  return (
    <div style={{ display: "flex", alignItems: "center", background: C.bg2, borderTop: `1.5px solid ${C.border}`, flexShrink: 0, paddingBottom: 16, boxShadow: "0 -4px 20px rgba(26,26,46,0.06)" }}>
      {leftTabs.map(n => <Tab key={n} name={n} />)}

      {/* Center camera — fun pill button */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", cursor: "pointer", marginTop: -22 }} onClick={onScan}>
        <div style={{
          width: 58, height: 58, borderRadius: "50%",
          background: `linear-gradient(135deg, ${C.teal}, ${C.mint})`,
          display: "flex", alignItems: "center", justifyContent: "center",
          boxShadow: `0 6px 24px ${C.teal}50, 0 0 0 4px ${C.bg2}`,
          border: `3px solid ${C.bg2}`,
          transition: "transform 0.15s, box-shadow 0.15s",
        }}>
          <svg width="26" height="26" fill="none" stroke="#fff" strokeWidth="2.2" viewBox="0 0 24 24">
            <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/>
            <circle cx="12" cy="13" r="4"/>
          </svg>
        </div>
      </div>

      {rightTabs.map(n => <Tab key={n} name={n} />)}
    </div>
  );
}

// ─────────────────────────────────────────────
//  ONBOARDING SCREENS
