// ONBOARDING PROGRESS BAR COMPONENT
function OnboardingProgress({ step, total }) {
  return (
    <div style={{ padding: "14px 24px 0", display: "flex", gap: 4 }}>
      {Array.from({ length: total }, (_, i) => (
        <div key={i} style={{ flex: 1, height: 3, borderRadius: 2, background: i <= step ? C.teal : "#1e1e1e", transition: "background 0.3s" }} />
      ))}
    </div>
  );
}

// ONBOARDING ORCHESTRATOR
function OnboardingFlow({ onComplete }) {
  const [step, setStep] = useState("splash"); // splash | carousel | auth | kitchen | taste | firstscan | welcome
  const [userName, setUserName] = useState("");

  const STEPS_WITH_PROGRESS = ["auth", "kitchen", "taste", "firstscan"];
  const stepIdx = STEPS_WITH_PROGRESS.indexOf(step);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
      {stepIdx >= 0 && (
        <OnboardingProgress step={stepIdx} total={STEPS_WITH_PROGRESS.length} />
      )}
      {step === "splash"    && <SplashScreen onDone={() => setStep("carousel")} />}
      {step === "carousel"  && <FeatureCarousel onDone={() => setStep("auth")} />}
      {step === "auth"      && <AuthScreen onDone={(name) => { if (name) setUserName(name); setStep("kitchen"); }} />}
      {step === "kitchen"   && <KitchenSetupScreen onDone={() => setStep("taste")} />}
      {step === "taste"     && <TasteProfileScreen onDone={() => setStep("firstscan")} />}
      {step === "firstscan" && <FirstScanPrompt onScan={() => setStep("welcome")} onSkip={() => setStep("welcome")} />}
      {step === "welcome"   && <WelcomeScreen userName={userName} onDone={onComplete} />}
    </div>
  );
}

