function AddWithAIScreen({ onBack, onSave }) {
  const [phase, setPhase] = useState("prompt"); // prompt | generating | result | editing
  const [prompt, setPrompt] = useState("");
  const [streamText, setStreamText] = useState("");
  const [genStep, setGenStep] = useState(0);
  const [recipe, setRecipe] = useState(null);
  const [editingField, setEditingField] = useState(null);
  const [saved, setSaved] = useState(false);
  const inputRef = useRef(null);

  const GEN_STEPS = [
    { label: "Understanding your request...", icon: "🧠" },
    { label: "Finding the right ingredients...", icon: "🥕" },
    { label: "Writing cooking steps...", icon: "👨‍🍳" },
    { label: "Checking your fridge...", icon: "🧊" },
    { label: "Finalising recipe...", icon: "✨" },
  ];

  const handleGenerate = () => {
    if (!prompt.trim()) return;
    setPhase("generating");
    setGenStep(0);

    // Animate through generation steps
    GEN_STEPS.forEach((_, i) => {
      setTimeout(() => setGenStep(i), i * 520);
    });

    // Stream in recipe title character by character
    const title = AI_GENERATED_RECIPE.title;
    let i = 0;
    const streamInterval = setInterval(() => {
      setStreamText(title.slice(0, i + 1));
      i++;
      if (i >= title.length) clearInterval(streamInterval);
    }, 40);

    setTimeout(() => {
      setRecipe(AI_GENERATED_RECIPE);
      setPhase("result");
    }, GEN_STEPS.length * 520 + 400);
  };

  const handleSave = () => {
    setSaved(true);
    setTimeout(onSave, 700);
  };

  // ── PROMPT PHASE ──
  if (phase === "prompt") {
    return (
      <div style={{ flex: 1, background: "#F8F7FF", display: "flex", flexDirection: "column", overflow: "hidden" }}>
        {/* Header */}
        <div style={{ padding: "16px 16px 0", display: "flex", alignItems: "center", gap: 12 }}>
          <BackBtn onBack={onBack} />
          <div>
            <div style={{ fontSize: 17, fontWeight: 500 }}>Add with kAI</div>
            <div style={{ fontSize: 11, color: `${C.purple}90`, marginTop: 1 }}>✦ Describe any recipe, kAI builds it</div>
          </div>
        </div>

        {/* Central prompt area */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center", padding: "0 20px 20px" }}>
          {/* Glow orb */}
          <div style={{ position: "relative", marginBottom: 32, textAlign: "center" }}>
            <div style={{ width: 80, height: 80, borderRadius: "50%", background: `radial-gradient(circle, ${C.purple}30 0%, transparent 70%)`, margin: "0 auto 16px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 36, border: `1px solid ${C.purple}30` }}>✨</div>
            <div style={{ fontSize: 20, fontWeight: 600, color: C.txt, letterSpacing: "-0.4px", marginBottom: 6 }}>What do you want to make?</div>
            <div style={{ fontSize: 13, color: C.muted, lineHeight: 1.5 }}>Type a dish name, describe what's in your fridge,<br />or paste any recipe text</div>
          </div>

          {/* Big prompt input */}
          <div style={{ background: C.lilacBg, border: `1.5px solid ${prompt ? C.purple : "#2a2540"}`, borderRadius: 18, padding: "16px 18px", marginBottom: 16, transition: "border-color 0.2s", boxShadow: prompt ? `0 0 20px ${C.purple}15` : "none" }}>
            <textarea
              ref={inputRef}
              value={prompt}
              onChange={e => setPrompt(e.target.value)}
              placeholder="e.g. Spaghetti carbonara, or 'something with eggs and spinach'..."
              rows={3}
              style={{ width: "100%", background: "transparent", border: "none", outline: "none", color: C.txt, fontSize: 15, resize: "none", lineHeight: 1.6, fontFamily: "system-ui, sans-serif" }}
            />
            {prompt && (
              <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 8 }}>
                <div onClick={() => setPrompt("")} style={{ color: "#444", fontSize: 11, cursor: "pointer" }}>Clear</div>
              </div>
            )}
          </div>

          {/* Quick suggestions */}
          <div style={{ fontSize: 10, color: "#333", textTransform: "uppercase", letterSpacing: "0.7px", marginBottom: 10 }}>Or try one of these</div>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 7, marginBottom: 28 }}>
            {PROMPT_SUGGESTIONS.map((s, i) => (
              <div key={i} onClick={() => setPrompt(s)} style={{ background: prompt === s ? `${C.purple}10` : C.card2, border: `1px solid ${prompt === s ? C.purple : C.border}`, borderRadius: 20, padding: "7px 12px", fontSize: 12, color: prompt === s ? C.purple : "#666", cursor: "pointer", transition: "all 0.15s" }}>
                {s}
              </div>
            ))}
          </div>

          {/* Three input modes */}
          <div style={{ display: "flex", gap: 8, marginBottom: 24 }}>
            {[{ icon: "💬", label: "Describe" }, { icon: "📋", label: "Paste text" }, { icon: "🧊", label: "Use my fridge" }].map(m => (
              <div key={m.label} style={{ flex: 1, background: C.lilacBg, border: "0.5px solid #1e1b30", borderRadius: 12, padding: "10px 6px", textAlign: "center", cursor: "pointer" }}>
                <div style={{ fontSize: 18, marginBottom: 4 }}>{m.icon}</div>
                <div style={{ fontSize: 10, color: C.muted }}>{m.label}</div>
              </div>
            ))}
          </div>

          {/* Generate CTA */}
          <div onClick={handleGenerate} style={{ background: prompt ? C.purple : "#1a1730", border: prompt ? "none" : "0.5px solid #2a2540", borderRadius: 16, padding: 16, textAlign: "center", color: prompt ? "#fff" : "#444", fontSize: 15, fontWeight: 600, cursor: prompt ? "pointer" : "default", transition: "all 0.25s", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, boxShadow: prompt ? `0 4px 24px ${C.purple}35` : "none" }}>
            <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>
            {prompt ? "Generate Recipe with kAI →" : "Type something to continue"}
          </div>
        </div>
      </div>
    );
  }

  // ── GENERATING PHASE ──
  if (phase === "generating") {
    return (
      <div style={{ flex: 1, background: "#F8F7FF", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "0 32px", textAlign: "center" }}>
        {/* Pulsing orb */}
        <div style={{ position: "relative", marginBottom: 36 }}>
          <div style={{ width: 100, height: 100, borderRadius: "50%", border: `1.5px solid ${C.purple}40`, display: "flex", alignItems: "center", justifyContent: "center", animation: "orbPulse 2s ease-in-out infinite" }}>
            <div style={{ width: 76, height: 76, borderRadius: "50%", background: `radial-gradient(circle, ${C.purple}15 0%, transparent 70%)`, border: `1px solid ${C.purple}20`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 34, background: C.purpleBg }}>
              {GEN_STEPS[genStep]?.icon}
            </div>
          </div>
        </div>

        {/* Streaming title */}
        {streamText && (
          <div style={{ fontSize: 22, fontWeight: 600, color: C.txt, letterSpacing: "-0.4px", marginBottom: 8, minHeight: 32 }}>
            {streamText}<span style={{ animation: "blink 0.8s step-end infinite", color: C.purple }}>|</span>
          </div>
        )}

        {/* Current step */}
        <div style={{ color: `${C.purple}90`, fontSize: 13, marginBottom: 32 }}>
          {GEN_STEPS[genStep]?.label}
        </div>

        {/* Step dots */}
        <div style={{ display: "flex", gap: 8 }}>
          {GEN_STEPS.map((step, i) => (
            <div key={i} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, opacity: i <= genStep ? 1 : 0.2, transition: "opacity 0.3s" }}>
              <div style={{ width: 28, height: 28, borderRadius: "50%", background: i < genStep ? C.purple : i === genStep ? `${C.purple}30` : "#1a1730", border: `1px solid ${i <= genStep ? C.purple : "#2a2540"}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, transition: "all 0.3s" }}>
                {i < genStep ? "✓" : step.icon}
              </div>
            </div>
          ))}
        </div>

        {/* Prompt echo */}
        <div style={{ marginTop: 32, background: C.lilacBg, border: "0.5px solid #1e1b30", borderRadius: 12, padding: "10px 16px", maxWidth: 280 }}>
          <div style={{ fontSize: 11, color: "#444", marginBottom: 3 }}>Your request</div>
          <div style={{ fontSize: 12, color: C.muted, fontStyle: "italic" }}>"{prompt}"</div>
        </div>

        <style>{`
          @keyframes orbPulse { 0%,100%{transform:scale(1);opacity:1} 50%{transform:scale(1.06);opacity:0.8} }
          @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }
        `}</style>
      </div>
    );
  }

  // ── RESULT PHASE ──
  if (!recipe) return null;
  const missing = recipe.ingredients.filter(i => !i.have);

  return (
    <div style={{ flex: 1, overflowY: "auto", background: C.bg }}>
      {/* Hero */}
      <div style={{ height: 170, background: "linear-gradient(160deg, #F5F3FF, #EDE9FE)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 70, position: "relative" }}>
        {recipe.emoji}
        <div style={{ position: "absolute", top: 12, left: 12 }}><BackBtn onBack={() => setPhase("prompt")} /></div>
        {/* AI badge */}
        <div style={{ position: "absolute", top: 12, right: 12, background: `${C.purple}25`, border: `0.5px solid ${C.purple}60`, borderRadius: 20, padding: "5px 12px", display: "flex", alignItems: "center", gap: 5 }}>
          <svg width="10" height="10" fill="none" stroke={C.purple} strokeWidth="2" viewBox="0 0 24 24"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>
          <span style={{ fontSize: 10, color: C.purple, fontWeight: 500 }}>kAI Generated</span>
        </div>
        {/* Prompt echo */}
        <div style={{ position: "absolute", bottom: 10, left: 12, right: 12, background: "rgba(0,0,0,0.5)", borderRadius: 10, padding: "4px 10px" }}>
          <span style={{ fontSize: 9, color: `${C.purple}90`, fontStyle: "italic" }}>"{prompt}"</span>
        </div>
      </div>

      <div style={{ padding: "14px 16px" }}>
        {/* Title — tappable to edit */}
        <div onClick={() => setEditingField("title")} style={{ marginBottom: 10 }}>
          {editingField === "title" ? (
            <input autoFocus defaultValue={recipe.title} onBlur={e => { setRecipe(r => ({ ...r, title: e.target.value })); setEditingField(null); }} style={{ fontSize: 22, fontWeight: 700, fontFamily: "'Fredoka', sans-serif", background: "transparent", border: `0.5px solid ${C.purple}`, borderRadius: 8, color: C.txt, outline: "none", width: "100%", padding: "4px 8px" }} />
          ) : (
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ fontSize: 22, fontWeight: 700, fontFamily: "'Fredoka', sans-serif" }}>{recipe.title}</span>
              <svg width="12" height="12" fill="none" stroke="#444" strokeWidth="2" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
            </div>
          )}
        </div>

        {/* Meta pills */}
        <div style={{ display: "flex", gap: 8, marginBottom: 14, flexWrap: "wrap" }}>
          {[`🕐 ${recipe.time}`, `👤 Serves ${recipe.serves}`, `⭐ ${recipe.diff}`, `🍽️ ${recipe.cuisine}`].map(t => (
            <div key={t} style={{ background: `${C.purple}15`, border: `0.5px solid ${C.purple}30`, borderRadius: 20, padding: "4px 10px", fontSize: 10, color: `${C.purple}cc` }}>{t}</div>
          ))}
        </div>

        {/* Fridge match banner */}
        {missing.length > 0 && (
          <div style={{ background: C.orangeBg, border: `0.5px solid ${C.orange}40`, borderRadius: 12, padding: "10px 12px", marginBottom: 14, display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ fontSize: 16 }}>🛒</span>
            <div style={{ flex: 1 }}>
              <div style={{ color: C.orange, fontSize: 11, fontWeight: 500 }}>Missing {missing.length} ingredients</div>
              <div style={{ color: `${C.orange}80`, fontSize: 10 }}>{missing.map(i => i.name).join(", ")}</div>
            </div>
            <div style={{ background: C.orange, color: "#2a1500", fontSize: 10, fontWeight: 500, padding: "4px 10px", borderRadius: 20, cursor: "pointer", whiteSpace: "nowrap" }}>Add to list</div>
          </div>
        )}

        {/* Ingredients */}
        <div style={{ fontSize: 10, color: "#444", textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 8 }}>Ingredients</div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginBottom: 16 }}>
          {recipe.ingredients.map((ing, i) => (
            <div key={i} style={{ background: ing.have ? C.card : "#2a1a0a", border: `0.5px solid ${ing.have ? C.border : C.orange + "50"}`, borderRadius: 10, padding: "8px 10px" }}>
              <div style={{ fontSize: 11, color: ing.have ? C.txt : C.orange }}>{ing.have ? "✓" : "✗"} {ing.name}</div>
              <div style={{ fontSize: 10, color: C.muted, marginTop: 2 }}>{ing.amount}</div>
            </div>
          ))}
        </div>

        {/* Steps */}
        <div style={{ fontSize: 10, color: "#444", textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 8 }}>Steps</div>
        {recipe.steps.map((step, i) => (
          <div key={i} style={{ display: "flex", gap: 12, marginBottom: 12 }}>
            <div style={{ width: 24, height: 24, background: C.purple, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, color: C.txt, fontWeight: 500, flexShrink: 0 }}>{i + 1}</div>
            <div style={{ color: C.muted, fontSize: 12, lineHeight: 1.6, paddingTop: 3 }}>{step}</div>
          </div>
        ))}

        {/* Regenerate nudge */}
        <div onClick={() => { setPhase("prompt"); setStreamText(""); setGenStep(0); }} style={{ background: C.lilacBg, border: `0.5px solid ${C.purple}30`, borderRadius: 12, padding: "10px 14px", marginBottom: 12, display: "flex", alignItems: "center", gap: 10, cursor: "pointer" }}>
          <svg width="14" height="14" fill="none" stroke={C.purple} strokeWidth="2" viewBox="0 0 24 24"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-3"/></svg>
          <span style={{ fontSize: 12, color: `${C.purple}90` }}>Not right? Regenerate or refine your prompt</span>
        </div>

        {/* Save */}
        <div onClick={handleSave} style={{ background: saved ? C.greenBg : C.purple, border: saved ? `0.5px solid ${C.green}` : "none", borderRadius: 14, padding: 15, textAlign: "center", color: saved ? C.green : "#fff", fontSize: 14, fontWeight: 600, cursor: "pointer", transition: "all 0.25s" }}>
          {saved ? "✓ Saved to Kollection!" : "Save to Kollection →"}
        </div>
      </div>
      <div style={{ height: 20 }} />
    </div>
  );
}

// ─────────────────────────────────────────────
//  ROOT
// ─────────────────────────────────────────────
export default function KaiLens() {
  const [hasOnboarded, setHasOnboarded] = useState(false);
  const [activeNav, setActiveNav] = useState("Kitchen");
  const [screen, setScreen] = useState("kitchen");
  const [activeTab, setActiveTab] = useState("fridge");
  const [toast, setToast] = useState(null);
  const [selectedPost, setSelectedPost] = useState(null);
  const [posts, setPosts] = useState(FEED_POSTS);
  const [scanMode, setScanMode] = useState("fridge");
  const [extractedRecipe, setExtractedRecipe] = useState(null);

  const showToast = msg => { setToast(msg); setTimeout(() => setToast(null), 2500); };
  const goTo = (s, nav) => { setScreen(s); if (nav) setActiveNav(nav); };
  const toggleLike = id => setPosts(ps => ps.map(p => p.id===id?{...p,liked:!p.liked,likes:p.liked?p.likes-1:p.likes+1}:p));
  const toggleSave = id => { setPosts(ps => ps.map(p => p.id===id?{...p,saved:!p.saved}:p)); showToast("Saved to Kollection!"); };

  const isFullscreen = screen === "scan" || screen === "scanresults";

  // Show onboarding until complete
  if (!hasOnboarded) {
    return (
      <div style={{ fontFamily: "'Nunito', 'Fredoka', system-ui, sans-serif", background: C.bg, minHeight: "100vh", maxWidth: 390, margin: "0 auto", display: "flex", flexDirection: "column", color: C.txt }}>
        <FontLoader />
      <OnboardingFlow onComplete={() => setHasOnboarded(true)} />
      </div>
    );
  }

  return (
    <div style={{ fontFamily: "'Nunito', 'Fredoka', system-ui, sans-serif", background: C.bg, minHeight: "100vh", maxWidth: 390, margin: "0 auto", display: "flex", flexDirection: "column", color: C.txt, position: "relative" }}>
      <FontLoader />
      {toast && <div style={{ position: "absolute", top: 20, left: "50%", transform: "translateX(-50%)", background: C.greenBg, border: `2px solid ${C.green}`, borderRadius: 999, padding: "10px 20px", zIndex: 100, whiteSpace: "nowrap", boxShadow: C.shadowMd }}><span style={{ color: C.green, fontSize: 12, fontWeight: 500 }}>✓ {toast}</span></div>}

      {screen==="feed"        && <FeedScreen posts={posts} onLike={toggleLike} onSave={toggleSave} onPost={p=>{setSelectedPost(p);goTo("post");}} onImport={()=>goTo("import","Kitchen")} onDiscover={()=>goTo("discover")} />}
      {screen==="discover"    && <DiscoverScreen />}
      {screen==="post"        && <PostScreen post={selectedPost} onBack={()=>goTo("feed","Kai")} />}
      {screen==="kitchen"     && <KitchenScreen activeTab={activeTab} setActiveTab={setActiveTab} onScan={()=>goTo("scanmode")} />}
      {screen==="scanmode"    && <ScanModeSelector onBack={()=>goTo("kitchen","Kitchen")} onSelect={mode=>{ if (mode==="receipt") { goTo("receiptscan"); } else { setScanMode(mode==="all"?"fridge":mode); goTo("scan"); }}} initialMode={activeTab} />}
      {screen==="scan"        && <ScanScreen onBack={()=>goTo("scanmode")} onDone={()=>goTo("scanresults")} scanMode={scanMode} />}
      {screen==="receiptscan" && <ReceiptScanScreen onBack={()=>goTo("scanmode")} onDone={()=>{showToast("Kitchen updated! 10 items added"); goTo("kitchen","Kitchen");}} />}
      {screen==="scanresults" && <ScanResults onBack={()=>goTo("scan")} onDone={()=>{showToast("Kitchen updated!"); goTo("kitchen","Kitchen");}} scanMode={scanMode} />}
      {screen==="suggestions" && <SuggestScreen onBack={()=>goTo("kitchen","Kitchen")} />}
      {screen==="import"      && <ImportScreen onBack={()=>goTo("kitchen","Kitchen")} onDone={(recipe)=>{ setExtractedRecipe(recipe); goTo("recipe"); }} />}
      {screen==="recipe"      && <RecipeScreen onBack={()=>goTo("import")} recipe={extractedRecipe} onSave={()=>{showToast("Saved to Kollection! 🎉");goTo("cookbook","Kollection");}} />}
      {screen==="cookbook"    && <CookBookScreen onRecipe={()=>goTo("recipe")} onImport={()=>goTo("import")} onSuggest={()=>goTo("suggestions")} onAddAI={()=>goTo("addai")} onCreate={()=>goTo("create")} />}
      {screen==="create"      && <CreateRecipeScreen onBack={()=>goTo("cookbook","Kollection")} onSave={()=>{showToast("Recipe created! 🎉"); goTo("cookbook","Kollection");}} />}
      {screen==="addai"       && <AddWithAIScreen onBack={()=>goTo("cookbook","Kollection")} onSave={()=>{showToast("Saved to Kollection!"); goTo("cookbook","Kollection");}} />}
      {screen==="planner"     && <PlannerScreen onShop={()=>showToast("Added to shopping list!")} />}
      {screen==="profile"     && <ProfileScreen />}

      {!isFullscreen && (
        <NavBar active={activeNav} onScan={()=>goTo("scanmode")} setActive={n => {
          setActiveNav(n);
          if (n==="Kai") goTo("feed");
          if (n==="Kalenda") goTo("planner","Kalenda");
          if (n==="Kitchen") goTo("kitchen");
          if (n==="Kollection") goTo("cookbook","Kollection");
          if (n==="Profile") goTo("profile");
        }} />
      )}
    </div>
  );
}
